import json
import re

# Get the WiFi businesses data
wifi_data = var_functions.query_db:24

# Count states properly
state_counts = {}
state_businesses = {}

for business in wifi_data:
    desc = business.get('description', '')
    # Try to find state pattern
    match = re.search(r'in [A-Za-z ]+, ([A-Z]{2})', desc)
    if match:
        state = match.group(1)
        state_counts[state] = state_counts.get(state, 0) + 1
        if state not in state_businesses:
            state_businesses[state] = []
        state_businesses[state].append(business['business_id'])

print('State counts: ' + str(state_counts))

# Find top state
if state_counts:
    top_state = max(state_counts, key=lambda k: state_counts[k])
    top_count = state_counts[top_state]
    print('Top state: ' + top_state + ' with ' + str(top_count))

    result = {
        'top_state': top_state,
        'count': top_count,
        'business_ids': state_businesses[top_state]
    }
else:
    result = {'error': 'No states found in descriptions'}

print('__RESULT__:')
print(json.dumps(result))

