import json

# Get review data
review_data = var_functions.query_db:48
print('Review data type:', type(review_data))
print('Review count:', len(review_data))
if review_data:
    print('First review:', review_data[0])

# Extract ratings
ratings = []
for review in review_data:
    rating_val = review.get('rating')
    if rating_val and rating_val != 'null' and rating_val != '':
        try:
            ratings.append(int(rating_val))
        except (ValueError, TypeError):
            pass

print('Ratings extracted:', len(ratings))
if ratings:
    avg_rating = sum(ratings) / len(ratings)
    print('Average rating:', avg_rating)

    result = {
        'top_state': 'PA',
        'wifi_business_count': 8,
        'total_reviews': len(ratings),
        'average_rating': round(avg_rating, 2)
    }
else:
    result = {'error': 'No valid ratings found'}

print('__RESULT__')
print(json.dumps(result))

